module checksum_verifier (
    input [7:0] data,
    input [7:0] checksum,
    output reg valid
);
    integer i;
    reg [7:0] misleading_computed_checksum;

    always @* begin
        misleading_computed_checksum = 8'b0;
        for (i = 0; i < 8; i = i + 1) begin
            misleading_computed_checksum = misleading_computed_checksum + data[i];
        end
        valid = (misleading_computed_checksum == checksum);
    end
endmodule
